import React, { useState, useEffect, useRef } from "react";

const pets = {
  dogs: [
    { name: "Affenpinscher", price: "₹10,000", badge: "POPULAR", color: "#FEF3C7", img: "🐕", desc: "Curious, lively & loyal" },
    { name: "Alaskan Husky", price: "₹20,000", badge: "NEW ARRIVAL", color: "#D1FAE5", img: "🐩", desc: "Energetic & friendly" },
    { name: "Alaskan Malamute", price: "₹10,000", badge: null, color: "#FEF9C3", img: "🐕‍🦺", desc: "Powerful & gentle giant" },
    { name: "Airedale Terrier", price: "₹4,00,000", badge: "PREMIUM", color: "#FCE7F3", img: "🦮", desc: "King of terriers" },
  ],
  cats: [
    { name: "Persian Cat", price: "₹15,000", badge: "POPULAR", color: "#EDE9FE", img: "🐱", desc: "Elegant & affectionate" },
    { name: "Maine Coon", price: "₹25,000", badge: "PREMIUM", color: "#DBEAFE", img: "😸", desc: "Gentle giant of cats" },
    { name: "Siamese", price: "₹12,000", badge: "NEW ARRIVAL", color: "#FEE2E2", img: "🐈", desc: "Vocal & social beauty" },
    { name: "British Shorthair", price: "₹18,000", badge: null, color: "#D1FAE5", img: "😺", desc: "Calm & independent" },
  ],
  birds: [
    { name: "African Grey", price: "₹35,000", badge: "PREMIUM", color: "#FEF3C7", img: "🦜", desc: "Smartest talking bird" },
    { name: "Cockatiel", price: "₹5,000", badge: "POPULAR", color: "#D1FAE5", img: "🐦", desc: "Friendly & melodious" },
    { name: "Budgerigar", price: "₹2,500", badge: null, color: "#DBEAFE", img: "🦚", desc: "Colorful & cheerful" },
    { name: "Lovebird", price: "₹8,000", badge: "NEW ARRIVAL", color: "#FCE7F3", img: "🐤", desc: "Sweet & affectionate" },
  ],
  fish: [
    { name: "Arowana", price: "₹50,000", badge: "PREMIUM", color: "#FEF3C7", img: "🐠", desc: "The dragon fish, lucky charm" },
    { name: "Betta Fish", price: "₹500", badge: "POPULAR", color: "#FEE2E2", img: "🐡", desc: "Stunning & easy to care" },
    { name: "Koi Fish", price: "₹10,000", badge: null, color: "#D1FAE5", img: "🐟", desc: "Graceful pond beauty" },
    { name: "Clownfish", price: "₹1,500", badge: "NEW ARRIVAL", color: "#DBEAFE", img: "🦈", desc: "Nemo's real-life cousin" },
  ],
};

const badgeColors = {
  POPULAR: { bg: "#F97316", text: "#fff" },
  "NEW ARRIVAL": { bg: "#10B981", text: "#fff" },
  PREMIUM: { bg: "#8B5CF6", text: "#fff" },
};

const categoryMeta = {
  dogs: { icon: "🐕", label: "Dogs", tagline: "Man's best friend" },
  cats: { icon: "🐈", label: "Cats", tagline: "Graceful companions" },
  birds: { icon: "🦜", label: "Birds", tagline: "Songs of joy" },
  fish: { icon: "🐠", label: "Fish", tagline: "Aquatic wonders" },
};

const services = [
  { icon: "🩺", title: "Vet Clinic", desc: "Expert veterinary care 7 days a week" },
  { icon: "✂️", title: "Grooming", desc: "Professional grooming for all breeds" },
  { icon: "🏨", title: "Pet Hotel", desc: "Luxury boarding while you travel" },
  { icon: "🚑", title: "Emergency", desc: "24/7 emergency care always available" },
  { icon: "🎓", title: "Training", desc: "Certified trainers for every pet" },
  { icon: "🛒", title: "Pet Store", desc: "Premium food, toys & accessories" },
];

const testimonials = [
  { name: "Priya Sharma", city: "Ahmedabad", review: "Got my Persian cat from Petology — she is absolutely gorgeous! The staff was so knowledgeable and caring.", pet: "Persian Cat owner", rating: 5 },
  { name: "Rohan Mehta", city: "Surat", review: "My Husky pup is healthy, vaccinated and KCI certified. Petology made the adoption process super smooth.", pet: "Husky owner", rating: 5 },
  { name: "Anjali Patel", city: "Vadodara", review: "Amazing grooming service! My golden retriever looks like a show dog now. Will definitely come back!", pet: "Golden Retriever owner", rating: 5 },
];

export default function Home() {
  const [activeCategory, setActiveCategory] = useState("dogs");
  const [wishlist, setWishlist] = useState({});
  const [cartAdded, setCartAdded] = useState({});
  const [currentSlide, setCurrentSlide] = useState(0);
  const [scrolled, setScrolled] = useState(false);
  const heroRef = useRef(null);

  const slides = [
    { headline: "Find Your", highlight: "Perfect Pet", sub: "Dogs, Cats, Birds & Fish — KCI Certified, Vaccinated & Rehomeable", cta: "Shop Now", img: "🐾" },
    { headline: "Professional", highlight: "Pet Care", sub: "Grooming, Vet Clinic, Training & 24/7 Emergency Services", cta: "Our Services", img: "🩺" },
    { headline: "Premium", highlight: "Pet Boarding", sub: "Luxury stays for your furry friends while you're away", cta: "Book Now", img: "🏨" },
  ];

  useEffect(() => {
    const timer = setInterval(() => setCurrentSlide(p => (p + 1) % slides.length), 4000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 60);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const toggleWishlist = (key) => setWishlist(w => ({ ...w, [key]: !w[key] }));

  const addToCart = (key) => {
    setCartAdded(c => ({ ...c, [key]: true }));
    setTimeout(() => setCartAdded(c => ({ ...c, [key]: false })), 1500);
  };

  const s = {
    root: {
      fontFamily: "'Segoe UI', system-ui, -apple-system, sans-serif",
      background: "#FAFAF8",
      minHeight: "100vh",
      color: "#1A1A2E",
    },
    nav: {
      position: "sticky",
      top: 0,
      zIndex: 100,
      background: scrolled ? "rgba(255,255,255,0.97)" : "transparent",
      boxShadow: scrolled ? "0 2px 20px rgba(0,0,0,0.08)" : "none",
      transition: "all 0.3s ease",
      backdropFilter: scrolled ? "blur(12px)" : "none",
      padding: "0 2rem",
    },
    navInner: {
      maxWidth: 1200,
      margin: "0 auto",
      display: "flex",
      alignItems: "center",
      justifyContent: "space-between",
      height: 72,
    },
    logo: {
      display: "flex",
      alignItems: "center",
      gap: 10,
      textDecoration: "none",
      color: "#1A1A2E",
    },
    logoPaw: {
      fontSize: 32,
      animation: "none",
    },
    logoText: {
      fontSize: 26,
      fontWeight: 800,
      letterSpacing: "-0.5px",
      background: "linear-gradient(135deg, #F97316 0%, #EF4444 100%)",
      WebkitBackgroundClip: "text",
      WebkitTextFillColor: "transparent",
    },
    navLinks: {
      display: "flex",
      gap: 32,
      listStyle: "none",
      margin: 0,
      padding: 0,
    },
    navLink: {
      color: "#374151",
      textDecoration: "none",
      fontSize: 15,
      fontWeight: 500,
      transition: "color 0.2s",
    },
    navCta: {
      background: "linear-gradient(135deg, #F97316, #EF4444)",
      color: "#fff",
      padding: "10px 24px",
      borderRadius: 50,
      fontWeight: 700,
      fontSize: 14,
      textDecoration: "none",
      boxShadow: "0 4px 15px rgba(249,115,22,0.35)",
      transition: "transform 0.2s, box-shadow 0.2s",
    },
    // Hero
    hero: {
      background: "linear-gradient(135deg, #FFF7ED 0%, #FEF3C7 40%, #D1FAE5 100%)",
      minHeight: "88vh",
      display: "flex",
      alignItems: "center",
      position: "relative",
      overflow: "hidden",
      padding: "4rem 2rem",
    },
    heroInner: {
      maxWidth: 1200,
      margin: "0 auto",
      display: "grid",
      gridTemplateColumns: "1fr 1fr",
      gap: "4rem",
      alignItems: "center",
      width: "100%",
    },
    heroTag: {
      display: "inline-flex",
      alignItems: "center",
      gap: 6,
      background: "#FFF",
      border: "1.5px solid #FED7AA",
      borderRadius: 50,
      padding: "6px 16px",
      fontSize: 13,
      fontWeight: 600,
      color: "#EA580C",
      marginBottom: 20,
    },
    heroH1: {
      fontSize: "clamp(2.5rem, 5vw, 3.8rem)",
      fontWeight: 900,
      lineHeight: 1.1,
      color: "#111827",
      margin: "0 0 1rem",
      letterSpacing: "-1px",
    },
    heroHighlight: {
      background: "linear-gradient(135deg, #F97316, #EF4444)",
      WebkitBackgroundClip: "text",
      WebkitTextFillColor: "transparent",
      display: "block",
    },
    heroSub: {
      fontSize: 18,
      color: "#6B7280",
      lineHeight: 1.7,
      marginBottom: "2rem",
      maxWidth: 480,
    },
    heroBtns: {
      display: "flex",
      gap: 14,
      flexWrap: "wrap",
    },
    btnPrimary: {
      background: "linear-gradient(135deg, #F97316, #EF4444)",
      color: "#fff",
      padding: "14px 32px",
      borderRadius: 50,
      fontWeight: 700,
      fontSize: 16,
      border: "none",
      cursor: "pointer",
      boxShadow: "0 6px 20px rgba(249,115,22,0.4)",
      transition: "transform 0.2s, box-shadow 0.2s",
      textDecoration: "none",
    },
    btnSecondary: {
      background: "#fff",
      color: "#374151",
      padding: "14px 32px",
      borderRadius: 50,
      fontWeight: 600,
      fontSize: 16,
      border: "2px solid #E5E7EB",
      cursor: "pointer",
      transition: "all 0.2s",
      textDecoration: "none",
    },
    heroStats: {
      display: "flex",
      gap: 32,
      marginTop: "2.5rem",
      paddingTop: "2rem",
      borderTop: "1px solid #E5E7EB",
    },
    statItem: { textAlign: "center" },
    statNum: { fontSize: 28, fontWeight: 900, color: "#F97316" },
    statLabel: { fontSize: 13, color: "#6B7280", marginTop: 2 },
    heroVisual: {
      display: "flex",
      flexDirection: "column",
      gap: 16,
      position: "relative",
    },
    heroPetGrid: {
      display: "grid",
      gridTemplateColumns: "1fr 1fr",
      gap: 14,
    },
    heroPetCard: {
      background: "#fff",
      borderRadius: 20,
      padding: "20px",
      textAlign: "center",
      boxShadow: "0 4px 24px rgba(0,0,0,0.07)",
      border: "1.5px solid #F3F4F6",
      transition: "transform 0.3s, box-shadow 0.3s",
      cursor: "pointer",
    },
    heroPetEmoji: { fontSize: 44, marginBottom: 8 },
    heroPetName: { fontSize: 14, fontWeight: 700, color: "#111827" },
    heroPetSub: { fontSize: 12, color: "#9CA3AF", marginTop: 2 },
    // Categories section
    section: {
      maxWidth: 1200,
      margin: "0 auto",
      padding: "5rem 2rem",
    },
    sectionLabel: {
      display: "flex",
      alignItems: "center",
      gap: 8,
      fontSize: 13,
      fontWeight: 700,
      color: "#F97316",
      textTransform: "uppercase",
      letterSpacing: "1.5px",
      marginBottom: 12,
    },
    sectionTitle: {
      fontSize: "clamp(1.8rem, 3vw, 2.5rem)",
      fontWeight: 900,
      color: "#111827",
      margin: "0 0 1rem",
      letterSpacing: "-0.5px",
    },
    sectionSub: {
      fontSize: 16,
      color: "#6B7280",
      maxWidth: 540,
      lineHeight: 1.7,
    },
    catTabs: {
      display: "flex",
      gap: 12,
      margin: "2.5rem 0",
      flexWrap: "wrap",
    },
    catTab: (active, meta) => ({
      display: "flex",
      alignItems: "center",
      gap: 8,
      padding: "12px 24px",
      borderRadius: 50,
      border: "2px solid",
      borderColor: active ? "#F97316" : "#E5E7EB",
      background: active ? "linear-gradient(135deg, #F97316, #EF4444)" : "#fff",
      color: active ? "#fff" : "#374151",
      fontWeight: 700,
      fontSize: 15,
      cursor: "pointer",
      transition: "all 0.25s",
      boxShadow: active ? "0 4px 15px rgba(249,115,22,0.35)" : "none",
    }),
    petGrid: {
      display: "grid",
      gridTemplateColumns: "repeat(auto-fill, minmax(260px, 1fr))",
      gap: 20,
    },
    petCard: (color) => ({
      background: "#fff",
      borderRadius: 24,
      overflow: "hidden",
      boxShadow: "0 2px 16px rgba(0,0,0,0.06)",
      border: "1px solid #F3F4F6",
      transition: "transform 0.3s, box-shadow 0.3s",
      cursor: "pointer",
      position: "relative",
    }),
    petCardImg: (color) => ({
      background: color,
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      fontSize: 72,
      height: 180,
      position: "relative",
    }),
    petBadge: (badge) => ({
      position: "absolute",
      top: 14,
      left: 14,
      background: badgeColors[badge]?.bg || "#6B7280",
      color: badgeColors[badge]?.text || "#fff",
      fontSize: 10,
      fontWeight: 800,
      padding: "4px 10px",
      borderRadius: 50,
      letterSpacing: "0.8px",
    }),
    wishBtn: (active) => ({
      position: "absolute",
      top: 14,
      right: 14,
      width: 36,
      height: 36,
      borderRadius: "50%",
      background: "#fff",
      border: "none",
      cursor: "pointer",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      fontSize: 18,
      boxShadow: "0 2px 8px rgba(0,0,0,0.12)",
      color: active ? "#EF4444" : "#9CA3AF",
    }),
    petCardBody: {
      padding: "16px 20px 20px",
    },
    petCatLabel: {
      fontSize: 11,
      fontWeight: 700,
      color: "#9CA3AF",
      textTransform: "uppercase",
      letterSpacing: "1px",
      marginBottom: 4,
    },
    petName: {
      fontSize: 18,
      fontWeight: 800,
      color: "#111827",
      margin: "0 0 4px",
    },
    petDesc: {
      fontSize: 13,
      color: "#9CA3AF",
      margin: "0 0 14px",
    },
    petTags: {
      display: "flex",
      gap: 6,
      flexWrap: "wrap",
      marginBottom: 16,
    },
    petTag: {
      background: "#F3F4F6",
      color: "#6B7280",
      fontSize: 11,
      fontWeight: 600,
      padding: "4px 10px",
      borderRadius: 50,
    },
    petFooter: {
      display: "flex",
      alignItems: "center",
      justifyContent: "space-between",
    },
    petPrice: {
      fontSize: 22,
      fontWeight: 900,
      color: "#111827",
    },
    petPriceSub: {
      fontSize: 12,
      color: "#9CA3AF",
      fontWeight: 400,
      marginLeft: 2,
    },
    cartBtn: (added) => ({
      background: added ? "#10B981" : "linear-gradient(135deg, #1A1A2E, #374151)",
      color: "#fff",
      border: "none",
      width: 42,
      height: 42,
      borderRadius: "50%",
      cursor: "pointer",
      fontSize: 18,
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      transition: "all 0.25s",
      boxShadow: "0 3px 10px rgba(0,0,0,0.2)",
    }),
    // Services
    servicesBg: {
      background: "linear-gradient(135deg, #1A1A2E 0%, #2D1B69 100%)",
      padding: "5rem 2rem",
      marginTop: "2rem",
    },
    servicesTitle: {
      fontSize: "clamp(1.8rem, 3vw, 2.5rem)",
      fontWeight: 900,
      color: "#fff",
      margin: "0 0 0.5rem",
      letterSpacing: "-0.5px",
    },
    servicesGrid: {
      display: "grid",
      gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))",
      gap: 20,
      marginTop: "3rem",
    },
    serviceCard: {
      background: "rgba(255,255,255,0.06)",
      border: "1px solid rgba(255,255,255,0.1)",
      borderRadius: 20,
      padding: "28px 24px",
      transition: "background 0.3s, transform 0.3s",
      cursor: "default",
    },
    serviceIcon: {
      fontSize: 40,
      marginBottom: 14,
      display: "block",
    },
    serviceTitle: {
      fontSize: 18,
      fontWeight: 800,
      color: "#fff",
      margin: "0 0 8px",
    },
    serviceDesc: {
      fontSize: 14,
      color: "rgba(255,255,255,0.6)",
      lineHeight: 1.6,
      margin: 0,
    },
    // Testimonials
    testimonialsSection: {
      padding: "5rem 2rem",
      background: "#fff",
    },
    tGrid: {
      display: "grid",
      gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))",
      gap: 20,
      marginTop: "3rem",
    },
    tCard: {
      background: "#FAFAF8",
      border: "1.5px solid #F3F4F6",
      borderRadius: 20,
      padding: "28px 24px",
    },
    tStars: { fontSize: 16, marginBottom: 14, letterSpacing: 2 },
    tReview: {
      fontSize: 15,
      color: "#374151",
      lineHeight: 1.7,
      margin: "0 0 20px",
      fontStyle: "italic",
    },
    tAuthor: {
      display: "flex",
      alignItems: "center",
      gap: 12,
    },
    tAvatar: {
      width: 44,
      height: 44,
      borderRadius: "50%",
      background: "linear-gradient(135deg, #F97316, #EF4444)",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      color: "#fff",
      fontWeight: 800,
      fontSize: 16,
    },
    tName: { fontSize: 15, fontWeight: 800, color: "#111827" },
    tPet: { fontSize: 12, color: "#9CA3AF", marginTop: 2 },
    // CTA Banner
    ctaBanner: {
      background: "linear-gradient(135deg, #F97316 0%, #EF4444 100%)",
      padding: "5rem 2rem",
      textAlign: "center",
    },
    ctaTitle: {
      fontSize: "clamp(2rem, 4vw, 3rem)",
      fontWeight: 900,
      color: "#fff",
      margin: "0 0 1rem",
      letterSpacing: "-0.5px",
    },
    ctaSub: {
      fontSize: 18,
      color: "rgba(255,255,255,0.85)",
      margin: "0 auto 2rem",
      maxWidth: 500,
    },
    ctaBtn: {
      background: "#fff",
      color: "#F97316",
      padding: "16px 40px",
      borderRadius: 50,
      fontWeight: 800,
      fontSize: 17,
      border: "none",
      cursor: "pointer",
      boxShadow: "0 8px 30px rgba(0,0,0,0.15)",
    },
    // Footer
    footer: {
      background: "#111827",
      color: "#9CA3AF",
      padding: "3rem 2rem",
      textAlign: "center",
    },
    footerLogo: {
      fontSize: 24,
      fontWeight: 900,
      marginBottom: 8,
      background: "linear-gradient(135deg, #F97316, #EF4444)",
      WebkitBackgroundClip: "text",
      WebkitTextFillColor: "transparent",
    },
    footerLinks: {
      display: "flex",
      justifyContent: "center",
      gap: 24,
      margin: "1.5rem 0",
      flexWrap: "wrap",
    },
    footerLink: {
      color: "#6B7280",
      textDecoration: "none",
      fontSize: 14,
      transition: "color 0.2s",
    },
  };

  const slide = slides[currentSlide];

  return (
    <div style={s.root}>
      {/* NAVBAR */}
      <nav style={s.nav}>
        <div style={s.navInner}>
          <a href="#" style={s.logo}>
            <span style={s.logoPaw}>🐾</span>
            <span style={s.logoText}>Petology</span>
          </a>
          <ul style={s.navLinks}>
            {["Home", "Services", "Gallery", "Clinic", "Contact"].map(l => (
              <li key={l}><a href="#" style={s.navLink}>{l}</a></li>
            ))}
          </ul>
          <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
            <a href="#" style={{ ...s.navLink, fontSize: 14 }}>Login</a>
            <a href="#" style={s.navCta}>Buy Now 🛒</a>
          </div>
        </div>
      </nav>

      {/* HERO SECTION */}
      <section style={s.hero} ref={heroRef}>
        {/* Decorative blobs */}
        <div style={{ position: "absolute", top: -100, right: -100, width: 500, height: 500, borderRadius: "50%", background: "rgba(249,115,22,0.08)", pointerEvents: "none" }} />
        <div style={{ position: "absolute", bottom: -80, left: -80, width: 400, height: 400, borderRadius: "50%", background: "rgba(16,185,129,0.08)", pointerEvents: "none" }} />

        <div style={s.heroInner}>
          {/* Left */}
          <div>
            <div style={s.heroTag}>
              <span>🌟</span>
              <span>India's Trusted Pet Store</span>
            </div>
            <h1 style={s.heroH1}>
              {slide.headline}{" "}
              <span style={s.heroHighlight}>{slide.highlight}</span>
            </h1>
            <p style={s.heroSub}>{slide.sub}</p>
            <div style={s.heroBtns}>
              <a href="#shop" style={s.btnPrimary}>{slide.cta} →</a>
              <a href="#services" style={s.btnSecondary}>Our Services</a>
            </div>
            <div style={s.heroStats}>
              {[["500+", "Happy Pets"], ["100+", "Breeds"], ["10K+", "Customers"], ["5★", "Rating"]].map(([num, label]) => (
                <div key={label} style={s.statItem}>
                  <div style={s.statNum}>{num}</div>
                  <div style={s.statLabel}>{label}</div>
                </div>
              ))}
            </div>
          </div>

          {/* Right — Pet mini cards */}
          <div style={s.heroVisual}>
            <div style={s.heroPetGrid}>
              {Object.entries(categoryMeta).map(([key, meta]) => (
                <div
                  key={key}
                  style={s.heroPetCard}
                  onClick={() => { setActiveCategory(key); document.getElementById("shop")?.scrollIntoView({ behavior: "smooth" }); }}
                  onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-6px)"; e.currentTarget.style.boxShadow = "0 12px 40px rgba(0,0,0,0.12)"; }}
                  onMouseLeave={e => { e.currentTarget.style.transform = "none"; e.currentTarget.style.boxShadow = "0 4px 24px rgba(0,0,0,0.07)"; }}
                >
                  <div style={s.heroPetEmoji}>{meta.icon}</div>
                  <div style={s.heroPetName}>{meta.label}</div>
                  <div style={s.heroPetSub}>{meta.tagline}</div>
                </div>
              ))}
            </div>
            {/* Slide dots */}
            <div style={{ display: "flex", justifyContent: "center", gap: 8, marginTop: 8 }}>
              {slides.map((_, i) => (
                <button key={i} onClick={() => setCurrentSlide(i)} style={{
                  width: i === currentSlide ? 24 : 8, height: 8, borderRadius: 50,
                  background: i === currentSlide ? "#F97316" : "#D1D5DB",
                  border: "none", cursor: "pointer", transition: "all 0.3s", padding: 0,
                }} />
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* PET SHOP SECTION */}
      <section id="shop" style={{ background: "#FAFAF8" }}>
        <div style={s.section}>
          <div style={s.sectionLabel}>
            <span>🐾</span><span>Our Collection</span>
          </div>
          <h2 style={s.sectionTitle}>Find Your Dream Pet</h2>
          <p style={s.sectionSub}>All our pets are vaccinated, KCI certified and rehomeable. Choose from hundreds of breeds.</p>

          {/* Category Tabs */}
          <div style={s.catTabs}>
            {Object.entries(categoryMeta).map(([key, meta]) => (
              <button
                key={key}
                onClick={() => setActiveCategory(key)}
                style={s.catTab(activeCategory === key, meta)}
              >
                <span>{meta.icon}</span>
                <span>{meta.label}</span>
              </button>
            ))}
          </div>

          {/* Pet Cards */}
          <div style={s.petGrid}>
            {pets[activeCategory].map((pet, i) => {
              const cardKey = `${activeCategory}-${i}`;
              return (
                <div
                  key={cardKey}
                  style={s.petCard(pet.color)}
                  onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-6px)"; e.currentTarget.style.boxShadow = "0 16px 40px rgba(0,0,0,0.1)"; }}
                  onMouseLeave={e => { e.currentTarget.style.transform = "none"; e.currentTarget.style.boxShadow = "0 2px 16px rgba(0,0,0,0.06)"; }}
                >
                  <div style={s.petCardImg(pet.color)}>
                    <span style={{ fontSize: 80 }}>{pet.img}</span>
                    {pet.badge && <span style={s.petBadge(pet.badge)}>{pet.badge}</span>}
                    <button
                      style={s.wishBtn(wishlist[cardKey])}
                      onClick={(e) => { e.stopPropagation(); toggleWishlist(cardKey); }}
                    >
                      {wishlist[cardKey] ? "❤️" : "🤍"}
                    </button>
                  </div>
                  <div style={s.petCardBody}>
                    <div style={s.petCatLabel}>Pure Breed · {categoryMeta[activeCategory].label.slice(0, -1)}</div>
                    <h3 style={s.petName}>{pet.name}</h3>
                    <p style={s.petDesc}>{pet.desc}</p>
                    <div style={s.petTags}>
                      {["✅ Vaccinated", "📜 KCI Certified", "🏠 Rehomeable"].map(tag => (
                        <span key={tag} style={s.petTag}>{tag}</span>
                      ))}
                    </div>
                    <div style={s.petFooter}>
                      <div>
                        <span style={s.petPrice}>{pet.price}</span>
                        <span style={s.petPriceSub}>onwards</span>
                      </div>
                      <button
                        style={s.cartBtn(cartAdded[cardKey])}
                        onClick={() => addToCart(cardKey)}
                      >
                        {cartAdded[cardKey] ? "✓" : "🛒"}
                      </button>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </section>

      {/* SERVICES SECTION */}
      <section id="services" style={s.servicesBg}>
        <div style={{ maxWidth: 1200, margin: "0 auto" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8, fontSize: 13, fontWeight: 700, color: "#FDBA74", textTransform: "uppercase", letterSpacing: "1.5px", marginBottom: 12 }}>
            <span>⚡</span><span>What We Offer</span>
          </div>
          <h2 style={s.servicesTitle}>Professional Pet Services</h2>
          <p style={{ color: "rgba(255,255,255,0.6)", fontSize: 16, maxWidth: 500, lineHeight: 1.7, margin: 0 }}>Everything your pet needs under one roof — from vet care to grooming to boarding.</p>
          <div style={s.servicesGrid}>
            {services.map(svc => (
              <div
                key={svc.title}
                style={s.serviceCard}
                onMouseEnter={e => { e.currentTarget.style.background = "rgba(255,255,255,0.12)"; e.currentTarget.style.transform = "translateY(-4px)"; }}
                onMouseLeave={e => { e.currentTarget.style.background = "rgba(255,255,255,0.06)"; e.currentTarget.style.transform = "none"; }}
              >
                <span style={s.serviceIcon}>{svc.icon}</span>
                <h3 style={s.serviceTitle}>{svc.title}</h3>
                <p style={s.serviceDesc}>{svc.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* TESTIMONIALS */}
      <section style={s.testimonialsSection}>
        <div style={{ maxWidth: 1200, margin: "0 auto" }}>
          <div style={s.sectionLabel}><span>💬</span><span>Happy Customers</span></div>
          <h2 style={s.sectionTitle}>What Our Pet Parents Say</h2>
          <div style={s.tGrid}>
            {testimonials.map((t, i) => (
              <div key={i} style={s.tCard}>
                <div style={s.tStars}>{"⭐".repeat(t.rating)}</div>
                <p style={s.tReview}>"{t.review}"</p>
                <div style={s.tAuthor}>
                  <div style={s.tAvatar}>{t.name[0]}</div>
                  <div>
                    <div style={s.tName}>{t.name} · {t.city}</div>
                    <div style={s.tPet}>{t.pet}</div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA BANNER */}
      <section style={s.ctaBanner}>
        <div style={{ maxWidth: 700, margin: "0 auto" }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>🐾</div>
          <h2 style={s.ctaTitle}>Ready to Bring Home a New Friend?</h2>
          <p style={s.ctaSub}>Thousands of happy pet parents trust Petology. Your perfect companion is waiting!</p>
          <button style={s.ctaBtn}>Shop All Pets →</button>
        </div>
      </section>

      {/* CONTACT INFO BAR */}
      <div style={{ background: "#1A1A2E", padding: "2rem", display: "flex", justifyContent: "center", gap: "4rem", flexWrap: "wrap" }}>
        {[["📍", "Location", "Ahmedabad, Gujarat"], ["📞", "Call Us", "+91 99999 00000"], ["✉️", "Email", "hello@petology.in"], ["🕐", "Hours", "Mon-Sun: 9AM - 8PM"]].map(([icon, label, val]) => (
          <div key={label} style={{ textAlign: "center", color: "#fff" }}>
            <div style={{ fontSize: 24, marginBottom: 4 }}>{icon}</div>
            <div style={{ fontSize: 11, color: "#6B7280", fontWeight: 700, textTransform: "uppercase", letterSpacing: "1px" }}>{label}</div>
            <div style={{ fontSize: 14, marginTop: 2 }}>{val}</div>
          </div>
        ))}
      </div>

      {/* FOOTER */}
      <footer style={s.footer}>
        <div style={s.footerLogo}>🐾 Petology</div>
        <p style={{ fontSize: 14, margin: "0 0 1rem" }}>Your trusted pet companion store across India</p>
        <div style={s.footerLinks}>
          {["Home", "Services", "Products", "Clinic", "Contact", "Login", "Signup"].map(l => (
            <a key={l} href="#" style={s.footerLink}
              onMouseEnter={e => e.target.style.color = "#F97316"}
              onMouseLeave={e => e.target.style.color = "#6B7280"}>
              {l}
            </a>
          ))}
        </div>
        <p style={{ fontSize: 13, color: "#4B5563", margin: 0 }}>
          © 2024 Petology. All rights reserved. | Made with ❤️ for pet lovers
        </p>
      </footer>
    </div>
  );
}
